 1	import React, { FC, useState } from 'react';
 2	
 3	import { VirtualMachineModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import Loading from '@kubevirt-utils/components/Loading/Loading';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getGPUDevices } from '@kubevirt-utils/resources/vm';
 8	import { isWindows } from '@kubevirt-utils/resources/vm/utils/operation-system/operationSystem';
 9	import { isEmpty } from '@kubevirt-utils/utils/utils';
10	import { RFBCreate } from '@novnc/novnc/lib/rfb';
11	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
12	import { Bullseye, Flex, FlexItem, Stack, StackItem } from '@patternfly/react-core';
13	
14	import { AccessConsoles } from './components/AccessConsoles/AccessConsoles';
15	import CloudInitCredentials from './components/CloudInitCredentials/CloudInitCredentials';
16	import DesktopViewer from './components/DesktopViewer/DesktopViewer';
17	import SerialConsoleConnector from './components/SerialConsole/SerialConsoleConnector';
18	import {
19	  DESKTOP_VIEWER_CONSOLE_TYPE,
20	  SERIAL_CONSOLE_TYPE,
21	  VNC_CONSOLE_TYPE,
22	  WSFactoryExtends,
23	} from './components/utils/ConsoleConsts';
24	import VncConsole from './components/vnc-console/VncConsole';
25	import { isHeadlessModeVMI } from './utils/utils';
26	
27	import './consoles.scss';
28	
29	type ConsolesProps = {
30	  consoleContainerClass?: string;
31	  isStandAlone?: boolean;
32	  vmi: V1VirtualMachineInstance;
33	};
34	
35	const Consoles: FC<ConsolesProps> = ({ consoleContainerClass, isStandAlone, vmi }) => {
36	  const { t } = useKubevirtTranslation();
37	  const [type, setType] = useState<string>(VNC_CONSOLE_TYPE);
38	  const [rfb, setRFB] = useState<RFBCreate>(null);
39	  const [serialSocket, setSerialSocket] = useState<WSFactoryExtends>(null);
40	  const [vm] = useK8sWatchResource<V1VirtualMachine>({
41	    groupVersionKind: VirtualMachineModelGroupVersionKind,
42	    name: vmi?.metadata?.name,
43	    namespace: vmi?.metadata?.namespace,
44	  });
45	  const isWindowsVM = isWindows(vmi);
46	  const gpus = getGPUDevices(vm);
47	  const isHeadlessMode = isHeadlessModeVMI(vmi);
48	
49	  if (!vmi?.metadata) {
50	    return (
51	      <Bullseye>
52	        <Loading />
53	      </Bullseye>
54	    );
55	  }
56	
57	  if (isHeadlessMode) {
58	    return <div>{t('Console is disabled in headless mode')}</div>;
59	  }
60	
61	  return (
62	    <Stack>
63	      <StackItem className="consoles-actions">
64	        <Flex className="consoles-actions-inner-flex">
65	          <FlexItem>
66	            {!isWindowsVM && <CloudInitCredentials isStandAlone={isStandAlone} vm={vm} />}
67	          </FlexItem>
68	          <FlexItem>
69	            <AccessConsoles
70	              isWindowsVM={isWindowsVM}
71	              rfb={rfb}
72	              serialSocket={serialSocket}
73	              setType={setType}
74	              type={type}
75	            />
76	          </FlexItem>
77	        </Flex>
78	      </StackItem>
79	      <StackItem className={consoleContainerClass}>
80	        {type === VNC_CONSOLE_TYPE && (
81	          <VncConsole hasGPU={!isEmpty(gpus)} onConnect={setRFB} vmi={vmi} />
82	        )}
83	        {type === SERIAL_CONSOLE_TYPE && (
84	          <SerialConsoleConnector onConnect={setSerialSocket} vmi={vmi} />
85	        )}
86	        {type === DESKTOP_VIEWER_CONSOLE_TYPE && <DesktopViewer vm={vm} vmi={vmi} />}
87	      </StackItem>
88	    </Stack>
89	  );
90	};
91	
92	export default Consoles;

